from pydantic_ai import StreamingAgent
from vex import StreamingValidator

@vex.streaming_validator
def validate_streaming_advice(chunk: str, context: dict) -> bool:
    # GDPR: Block PII in streaming chunks
    if any(pii in chunk.lower() for pii in ['ssn', 'passport', 'card']):
        return False
    # SEC: Ensure disclaimer appears early
    if 'recommendation' in context and 'disclaimer' not in context:
        if 'not financial advice' not in chunk.lower():
            return False
    return True

streaming_agent = StreamingAgent(
    'gpt-4o',
    stream_validator=validate_streaming_advice
)

response = streaming_agent.run('Analyze portfolio: AAPL,TSLA')
for chunk in response:
    print(chunk)
